var e=JSON.parse(`[{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"여긴……?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"정신이 들어, 소령? 여긴 아이기스의 내부야.","JPN":"気が付いたか、少佐？　ここはアイギスの艦内だ。","ENG":"Are you awake, Major? You're in Aegis.","TWN":"你醒了，少校？這裡是埃癸斯的內艙。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"안토노프 양이 우릴 구해줘서…… 지금 우리는 이면세계를 표류하고 있어.","JPN":"アントノフさんが僕たちを助けてくれて……今裏世界を漂流している。","ENG":"Antonov saved us... We're currently drifting in Counterside.","TWN":"安東諾夫救了我們……現在我們正在異界漂流。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이면세계?","JPN":"裏世界？","ENG":"Counterside?","TWN":"異界？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Kgh!","TWN":"咳呃！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아, 아직 움직이지 않는 게 좋아. 전신 타박상에, 피도 많이 흘렸으니까.","JPN":"あ、まだ動かない方がいいよ。全身に打撲傷があって、出血も酷かったから。","ENG":"Ah, you'd better not move. You're bruised all over and have lost a lot of blood.","TWN":"先不要亂動，你全身多處挫傷，還流了好多血。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그리고 저, 그 눈은…….","JPN":"それから、その目なんだけど……","ENG":"And, uh... your right eye...","TWN":"還有那個，你的眼睛……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알고 있어요. 찔렸을 때부터, 직감했으니까.","JPN":"わかっています。刺された時点で直感しましたから。","ENG":"I know. I knew the moment it got stabbed.","TWN":"我知道，被擊中的時候，我就感覺到了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"더는 싸울 수 없겠죠. 주안을 잃어버린 저격수는.","JPN":"もう戦えないですよね。主眼を失った狙撃手は。","ENG":"There is no place on the battlefield for a sniper who has lost her dominant eye.","TWN":"一個失去主眼的狙擊手，我已經無法再戰鬥了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"괜찮아요, 박사님. 이제 전 싸울 생각 없으니까요.","JPN":"大丈夫です、博士。私はもう戦うつもりはありませんから。","ENG":"It's all right, Doctor. I have no intention of fighting anymore.","TWN":"沒關係，博士。我也不想繼續戰鬥了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우린 할 만큼 했어요.","JPN":"私たちは十分頑張りました。","ENG":"We did what we could.","TWN":"我們已經盡力了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까, 이젠 결과를 받아들여요.","JPN":"だから、もう結末を受け入れましょう。","ENG":"It's time... we accepted the outcome.","TWN":"所以，現在就接受結果吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"무슨 헛소리를 하는 거야! 결과를 받아들여? 무슨 결과!","JPN":"何を訳のわかんないこと言ってんだよ！　結末を受け入れるだ？　なんの結末だよ！","ENG":"What kind of nonsense is that? Accept the outcome? What outcome?!","TWN":"你在說什麼鬼話！接受結果？什麼結果！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"아직 아무것도 안 끝났어! 승부는 9회말 2아웃까지 모르는 거라고!","JPN":"まだ何も終わっちゃいない！　勝負は9回裏2アウトまでわからないもんだろ！","ENG":"Nothing's over yet! The real competition starts with 2 outs in the bottom of the 9th inning!","TWN":"一切都還沒結束呢！勝負是從九局下半二出局開始的！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"현실세계에서 마스터는 지금 아포리아와 목숨을 걸고 싸우고 있어!","JPN":"マスターは今、現実世界でアポリアと命懸けで戦ってるんだ！","ENG":"Master is in Normalside fighting with Aporia right now!","TWN":"大姊還在現世中與阿波利亞殊死對決！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};